    """

    def norm_string(value):
        # JSON-compliant escape sequence validation and processing
        result = []
        i = 0
        while i < len(value):
            if value[i] == '\\':
                if i + 1 >= len(value):
                    raise ConfigException("Unexpected end of string after backslash")

                next_char = value[i + 1]
                if next_char == '"':
                    result.append('"')
                    i += 2
                elif next_char == '\\':
                    result.append('\\')
                    i += 2
                elif next_char == '/':
                    result.append('/')
                    i += 2
                elif next_char == 'b':
