                elif next_char == 'f':
                    result.append('\f')
                    i += 2
                elif next_char == 'n':
                    result.append('\n')
                    i += 2
                elif next_char == 'r':
                    result.append('\r')
                    i += 2
                elif next_char == 't':
                    result.append('\t')
                elif next_char == 'u':
                    # Unicode escape \uXXXX
                    if i + 5 >= len(value):
                        raise ConfigException("Invalid unicode escape sequence")
                    unicode_hex = value[i + 2:i + 6]
