                        i += 6
                    except ValueError:
                        raise ConfigException("Invalid unicode escape sequence: \\u{}".format(unicode_hex))
                else:
                    # Invalid escape sequence
                    raise ConfigException("Invalid escape sequence: \\{}".format(next_char))
            else:
                result.append(value[i])
